import path from"node:path";import{getText}from"../httpUtil.js";import{BrowserPlatform}from"./types.js";function archive(r,e){switch(r){case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return"chrome-linux";case BrowserPlatform.MAC_ARM:case BrowserPlatform.MAC:return"chrome-mac";case BrowserPlatform.WIN32:case BrowserPlatform.WIN64:return parseInt(e,10)>591479?"chrome-win":"chrome-win32"}}function folder(r){switch(r){case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return"Linux_x64";case BrowserPlatform.MAC_ARM:return"Mac_Arm";case BrowserPlatform.MAC:return"Mac";case BrowserPlatform.WIN32:return"Win";case BrowserPlatform.WIN64:return"Win_x64"}}export function resolveDownloadUrl(r,e,o="https://storage.googleapis.com/chromium-browser-snapshots"){return`${o}/${resolveDownloadPath(r,e).join("/")}`}export function resolveDownloadPath(r,e){return[folder(r),e,`${archive(r,e)}.zip`]}export function relativeExecutablePath(r,e){switch(r){case BrowserPlatform.MAC:case BrowserPlatform.MAC_ARM:return path.join("chrome-mac","Chromium.app","Contents","MacOS","Chromium");case BrowserPlatform.LINUX_ARM:case BrowserPlatform.LINUX:return path.join("chrome-linux","chrome");case BrowserPlatform.WIN32:case BrowserPlatform.WIN64:return path.join("chrome-win","chrome.exe")}}export async function resolveBuildId(r){return await getText(new URL(`https://storage.googleapis.com/chromium-browser-snapshots/${folder(r)}/LAST_CHANGE`))}export function compareVersions(r,e){return Number(r)-Number(e)}